<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'; import { serviceApi } from '@/api/services'; import PageState from '@/shared/PageState.vue'; import { date } from '@/shared/format'
const loading=ref(true),error=ref(''),tickets=ref<any[]>([]),show=ref(false),saving=ref(false),form=reactive({subject:'',level:1,message:''});async function load(){loading.value=true;try{const r=await serviceApi.tickets();tickets.value=Array.isArray(r)?r:r?.data||[]}catch(e:any){error.value=e.message}finally{loading.value=false}}async function create(){saving.value=true;try{await serviceApi.createTicket(form);show.value=false;Object.assign(form,{subject:'',level:1,message:''});load()}catch(e:any){error.value=e.message}finally{saving.value=false}}onMounted(load)
</script>
<template><PageState :loading="loading" :error="error" @retry="load"><div class="page-heading"><div><h1>我的工单</h1><p>和技术支持团队沟通并跟进问题。</p></div><button class="button primary" @click="show=true">新的工单</button></div><section class="panel list-panel"><article v-for="item in tickets" :key="item.id"><div><strong>{{item.subject}}</strong><p>{{item.message||'等待查看详情'}}</p></div><div><span class="status">{{item.status===0?'待回复':item.status===1?'已回复':'已关闭'}}</span><time>{{date(item.updated_at||item.created_at,true)}}</time></div></article><div v-if="!tickets.length" class="page-state">暂无工单</div></section><div v-if="show" class="modal-backdrop" @click.self="show=false"><form class="modal" @submit.prevent="create"><header><div><h2>新的工单</h2><p>请描述你遇到的问题</p></div><button type="button" class="icon-button" @click="show=false">×</button></header><label>主题<input v-model="form.subject" required /></label><label>等级<select v-model="form.level"><option :value="0">低</option><option :value="1">中</option><option :value="2">高</option></select></label><label>消息<textarea v-model="form.message" rows="5" required /></label><footer><button type="button" class="button secondary" @click="show=false">取消</button><button class="button primary" :disabled="saving">{{saving?'正在提交':'提交'}}</button></footer></form></div></PageState></template>
